/**
 * @file fft_radix12_avx512_ct_n1_scaled.h
 * @brief DFT-12 AVX512 n1_scaled (separate is/os, output *= scale)
 *
 * FFTW-style codelet for recursive CT executor.
 * Generated by gen_radix12.py --variant ct_n1_scaled
 */

#ifndef FFT_RADIX12_AVX512_CT_CT_N1_SCALED_H
#define FFT_RADIX12_AVX512_CT_CT_N1_SCALED_H

#include <immintrin.h>

#ifndef FFT_W12_TWIDDLES_DEFINED
#define FFT_W12_TWIDDLES_DEFINED
static const double W12_1_re = 8.66025403784438707611e-01;
static const double W12_1_im = -4.99999999999999944489e-01;
static const double W12_2_re = 5.00000000000000111022e-01;
static const double W12_2_im = -8.66025403784438596588e-01;
static const double W12_3_re = 6.12323399573676603587e-17;
static const double W12_3_im = -1.00000000000000000000e+00;
static const double W12_4_re = -4.99999999999999777955e-01;
static const double W12_4_im = -8.66025403784438707611e-01;
static const double W12_6_re = -1.00000000000000000000e+00;
static const double W12_6_im = -1.22464679914735320717e-16;
#endif

#ifndef R12L_CT_LD
#define R12L_CT_LD(p) _mm512_loadu_pd(p)
#define R12L_CT_ST(p,v) _mm512_storeu_pd((p),(v))
#endif
#define LD R12L_CT_LD
#define ST R12L_CT_ST

static __attribute__((target("avx512f,avx512dq,fma"))) void
radix12_n1_scaled_fwd_avx512(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    size_t is, size_t os, size_t vl, double scale)
{
    const __m512d sign_flip = _mm512_set1_pd(-0.0);
    const __m512d KHALF = _mm512_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m512d KS = _mm512_set1_pd(0.866025403784438596588302061718422919511795044);

    __attribute__((aligned(64))) double spill_re[96];
    __attribute__((aligned(64))) double spill_im[96];

    __m512d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im;

    const __m512d tw_W12_1_re = _mm512_set1_pd(W12_1_re);
    const __m512d tw_W12_1_im = _mm512_set1_pd(W12_1_im);
    const __m512d tw_W12_2_re = _mm512_set1_pd(W12_2_re);
    const __m512d tw_W12_2_im = _mm512_set1_pd(W12_2_im);
    const __m512d tw_W12_4_re = _mm512_set1_pd(W12_4_re);
    const __m512d tw_W12_4_im = _mm512_set1_pd(W12_4_im);

    const __m512d vscale = _mm512_set1_pd(scale);

    for (size_t k = 0; k < vl; k += 8) {
        /* sub-FFT n2=0 */
        x0_re = LD(&in_re[0*is+k]);
        x0_im = LD(&in_im[0*is+k]);
        x1_re = LD(&in_re[3*is+k]);
        x1_im = LD(&in_im[3*is+k]);
        x2_re = LD(&in_re[6*is+k]);
        x2_im = LD(&in_im[6*is+k]);
        x3_re = LD(&in_re[9*is+k]);
        x3_im = LD(&in_im[9*is+k]);

        /* radix-4 n2=0 [fwd] */
        {
        __m512d sr=_mm512_add_pd(x0_re,x2_re), si=_mm512_add_pd(x0_im,x2_im);
        __m512d dr=_mm512_sub_pd(x0_re,x2_re), di=_mm512_sub_pd(x0_im,x2_im);
        __m512d tr=_mm512_add_pd(x1_re,x3_re), ti=_mm512_add_pd(x1_im,x3_im);
        __m512d ur=_mm512_sub_pd(x1_re,x3_re), ui=_mm512_sub_pd(x1_im,x3_im);
        x0_re=_mm512_add_pd(sr,tr); x0_im=_mm512_add_pd(si,ti);
        x2_re=_mm512_sub_pd(sr,tr); x2_im=_mm512_sub_pd(si,ti);
        x1_re=_mm512_add_pd(dr,ui); x1_im=_mm512_sub_pd(di,ur);
        x3_re=_mm512_sub_pd(dr,ui); x3_im=_mm512_add_pd(di,ur);
        }

        _mm512_store_pd(&spill_re[0*8], x0_re);
        _mm512_store_pd(&spill_im[0*8], x0_im);
        _mm512_store_pd(&spill_re[1*8], x1_re);
        _mm512_store_pd(&spill_im[1*8], x1_im);
        _mm512_store_pd(&spill_re[2*8], x2_re);
        _mm512_store_pd(&spill_im[2*8], x2_im);
        _mm512_store_pd(&spill_re[3*8], x3_re);
        _mm512_store_pd(&spill_im[3*8], x3_im);

        /* sub-FFT n2=1 */
        x0_re = LD(&in_re[1*is+k]);
        x0_im = LD(&in_im[1*is+k]);
        x1_re = LD(&in_re[4*is+k]);
        x1_im = LD(&in_im[4*is+k]);
        x2_re = LD(&in_re[7*is+k]);
        x2_im = LD(&in_im[7*is+k]);
        x3_re = LD(&in_re[10*is+k]);
        x3_im = LD(&in_im[10*is+k]);

        /* radix-4 n2=1 [fwd] */
        {
        __m512d sr=_mm512_add_pd(x0_re,x2_re), si=_mm512_add_pd(x0_im,x2_im);
        __m512d dr=_mm512_sub_pd(x0_re,x2_re), di=_mm512_sub_pd(x0_im,x2_im);
        __m512d tr=_mm512_add_pd(x1_re,x3_re), ti=_mm512_add_pd(x1_im,x3_im);
        __m512d ur=_mm512_sub_pd(x1_re,x3_re), ui=_mm512_sub_pd(x1_im,x3_im);
        x0_re=_mm512_add_pd(sr,tr); x0_im=_mm512_add_pd(si,ti);
        x2_re=_mm512_sub_pd(sr,tr); x2_im=_mm512_sub_pd(si,ti);
        x1_re=_mm512_add_pd(dr,ui); x1_im=_mm512_sub_pd(di,ur);
        x3_re=_mm512_sub_pd(dr,ui); x3_im=_mm512_add_pd(di,ur);
        }

        _mm512_store_pd(&spill_re[4*8], x0_re);
        _mm512_store_pd(&spill_im[4*8], x0_im);
        _mm512_store_pd(&spill_re[5*8], x1_re);
        _mm512_store_pd(&spill_im[5*8], x1_im);
        _mm512_store_pd(&spill_re[6*8], x2_re);
        _mm512_store_pd(&spill_im[6*8], x2_im);
        _mm512_store_pd(&spill_re[7*8], x3_re);
        _mm512_store_pd(&spill_im[7*8], x3_im);

        /* sub-FFT n2=2 */
        x0_re = LD(&in_re[2*is+k]);
        x0_im = LD(&in_im[2*is+k]);
        x1_re = LD(&in_re[5*is+k]);
        x1_im = LD(&in_im[5*is+k]);
        x2_re = LD(&in_re[8*is+k]);
        x2_im = LD(&in_im[8*is+k]);
        x3_re = LD(&in_re[11*is+k]);
        x3_im = LD(&in_im[11*is+k]);

        /* radix-4 n2=2 [fwd] */
        {
        __m512d sr=_mm512_add_pd(x0_re,x2_re), si=_mm512_add_pd(x0_im,x2_im);
        __m512d dr=_mm512_sub_pd(x0_re,x2_re), di=_mm512_sub_pd(x0_im,x2_im);
        __m512d tr=_mm512_add_pd(x1_re,x3_re), ti=_mm512_add_pd(x1_im,x3_im);
        __m512d ur=_mm512_sub_pd(x1_re,x3_re), ui=_mm512_sub_pd(x1_im,x3_im);
        x0_re=_mm512_add_pd(sr,tr); x0_im=_mm512_add_pd(si,ti);
        x2_re=_mm512_sub_pd(sr,tr); x2_im=_mm512_sub_pd(si,ti);
        x1_re=_mm512_add_pd(dr,ui); x1_im=_mm512_sub_pd(di,ur);
        x3_re=_mm512_sub_pd(dr,ui); x3_im=_mm512_add_pd(di,ur);
        }

        _mm512_store_pd(&spill_re[8*8], x0_re);
        _mm512_store_pd(&spill_im[8*8], x0_im);
        _mm512_store_pd(&spill_re[9*8], x1_re);
        _mm512_store_pd(&spill_im[9*8], x1_im);
        _mm512_store_pd(&spill_re[10*8], x2_re);
        _mm512_store_pd(&spill_im[10*8], x2_im);
        _mm512_store_pd(&spill_re[11*8], x3_re);
        _mm512_store_pd(&spill_im[11*8], x3_im);

        /* PASS 2: 4x radix-3 columns */

        /* column k1=0 */
        x0_re = _mm512_load_pd(&spill_re[0*8]);
        x0_im = _mm512_load_pd(&spill_im[0*8]);
        x1_re = _mm512_load_pd(&spill_re[4*8]);
        x1_im = _mm512_load_pd(&spill_im[4*8]);
        x2_re = _mm512_load_pd(&spill_re[8*8]);
        x2_im = _mm512_load_pd(&spill_im[8*8]);

        /* radix-3 k1=0 [fwd] */
        {
        __m512d sr=_mm512_add_pd(x1_re,x2_re), si=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm512_add_pd(x0_re,sr); x0_im=_mm512_add_pd(x0_im,si);
        x1_re=_mm512_fmadd_pd(KS,di,Rr); x1_im=_mm512_fnmadd_pd(KS,dr,Ri);
        x2_re=_mm512_fnmadd_pd(KS,di,Rr); x2_im=_mm512_fmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[0*os+k], _mm512_mul_pd(vscale, x0_re));
        ST(&out_im[0*os+k], _mm512_mul_pd(vscale, x0_im));
        ST(&out_re[4*os+k], _mm512_mul_pd(vscale, x1_re));
        ST(&out_im[4*os+k], _mm512_mul_pd(vscale, x1_im));
        ST(&out_re[8*os+k], _mm512_mul_pd(vscale, x2_re));
        ST(&out_im[8*os+k], _mm512_mul_pd(vscale, x2_im));

        /* column k1=1 */
        x0_re = _mm512_load_pd(&spill_re[1*8]);
        x0_im = _mm512_load_pd(&spill_im[1*8]);
        x1_re = _mm512_load_pd(&spill_re[5*8]);
        x1_im = _mm512_load_pd(&spill_im[5*8]);
        x2_re = _mm512_load_pd(&spill_re[9*8]);
        x2_im = _mm512_load_pd(&spill_im[9*8]);

        { __m512d tr = x1_re;
          x1_re = _mm512_fmsub_pd(x1_re,tw_W12_1_re,_mm512_mul_pd(x1_im,tw_W12_1_im));
          x1_im = _mm512_fmadd_pd(tr,tw_W12_1_im,_mm512_mul_pd(x1_im,tw_W12_1_re)); }
        { __m512d tr = x2_re;
          x2_re = _mm512_fmsub_pd(x2_re,tw_W12_2_re,_mm512_mul_pd(x2_im,tw_W12_2_im));
          x2_im = _mm512_fmadd_pd(tr,tw_W12_2_im,_mm512_mul_pd(x2_im,tw_W12_2_re)); }

        /* radix-3 k1=1 [fwd] */
        {
        __m512d sr=_mm512_add_pd(x1_re,x2_re), si=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm512_add_pd(x0_re,sr); x0_im=_mm512_add_pd(x0_im,si);
        x1_re=_mm512_fmadd_pd(KS,di,Rr); x1_im=_mm512_fnmadd_pd(KS,dr,Ri);
        x2_re=_mm512_fnmadd_pd(KS,di,Rr); x2_im=_mm512_fmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[1*os+k], _mm512_mul_pd(vscale, x0_re));
        ST(&out_im[1*os+k], _mm512_mul_pd(vscale, x0_im));
        ST(&out_re[5*os+k], _mm512_mul_pd(vscale, x1_re));
        ST(&out_im[5*os+k], _mm512_mul_pd(vscale, x1_im));
        ST(&out_re[9*os+k], _mm512_mul_pd(vscale, x2_re));
        ST(&out_im[9*os+k], _mm512_mul_pd(vscale, x2_im));

        /* column k1=2 */
        x0_re = _mm512_load_pd(&spill_re[2*8]);
        x0_im = _mm512_load_pd(&spill_im[2*8]);
        x1_re = _mm512_load_pd(&spill_re[6*8]);
        x1_im = _mm512_load_pd(&spill_im[6*8]);
        x2_re = _mm512_load_pd(&spill_re[10*8]);
        x2_im = _mm512_load_pd(&spill_im[10*8]);

        { __m512d tr = x1_re;
          x1_re = _mm512_fmsub_pd(x1_re,tw_W12_2_re,_mm512_mul_pd(x1_im,tw_W12_2_im));
          x1_im = _mm512_fmadd_pd(tr,tw_W12_2_im,_mm512_mul_pd(x1_im,tw_W12_2_re)); }
        { __m512d tr = x2_re;
          x2_re = _mm512_fmsub_pd(x2_re,tw_W12_4_re,_mm512_mul_pd(x2_im,tw_W12_4_im));
          x2_im = _mm512_fmadd_pd(tr,tw_W12_4_im,_mm512_mul_pd(x2_im,tw_W12_4_re)); }

        /* radix-3 k1=2 [fwd] */
        {
        __m512d sr=_mm512_add_pd(x1_re,x2_re), si=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm512_add_pd(x0_re,sr); x0_im=_mm512_add_pd(x0_im,si);
        x1_re=_mm512_fmadd_pd(KS,di,Rr); x1_im=_mm512_fnmadd_pd(KS,dr,Ri);
        x2_re=_mm512_fnmadd_pd(KS,di,Rr); x2_im=_mm512_fmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[2*os+k], _mm512_mul_pd(vscale, x0_re));
        ST(&out_im[2*os+k], _mm512_mul_pd(vscale, x0_im));
        ST(&out_re[6*os+k], _mm512_mul_pd(vscale, x1_re));
        ST(&out_im[6*os+k], _mm512_mul_pd(vscale, x1_im));
        ST(&out_re[10*os+k], _mm512_mul_pd(vscale, x2_re));
        ST(&out_im[10*os+k], _mm512_mul_pd(vscale, x2_im));

        /* column k1=3 */
        x0_re = _mm512_load_pd(&spill_re[3*8]);
        x0_im = _mm512_load_pd(&spill_im[3*8]);
        x1_re = _mm512_load_pd(&spill_re[7*8]);
        x1_im = _mm512_load_pd(&spill_im[7*8]);
        x2_re = _mm512_load_pd(&spill_re[11*8]);
        x2_im = _mm512_load_pd(&spill_im[11*8]);

        { __m512d tr = x1_re; x1_re = x1_im; x1_im = _mm512_xor_pd(tr,sign_flip); }
        x2_re = _mm512_xor_pd(x2_re,sign_flip); x2_im = _mm512_xor_pd(x2_im,sign_flip);

        /* radix-3 k1=3 [fwd] */
        {
        __m512d sr=_mm512_add_pd(x1_re,x2_re), si=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm512_add_pd(x0_re,sr); x0_im=_mm512_add_pd(x0_im,si);
        x1_re=_mm512_fmadd_pd(KS,di,Rr); x1_im=_mm512_fnmadd_pd(KS,dr,Ri);
        x2_re=_mm512_fnmadd_pd(KS,di,Rr); x2_im=_mm512_fmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[3*os+k], _mm512_mul_pd(vscale, x0_re));
        ST(&out_im[3*os+k], _mm512_mul_pd(vscale, x0_im));
        ST(&out_re[7*os+k], _mm512_mul_pd(vscale, x1_re));
        ST(&out_im[7*os+k], _mm512_mul_pd(vscale, x1_im));
        ST(&out_re[11*os+k], _mm512_mul_pd(vscale, x2_re));
        ST(&out_im[11*os+k], _mm512_mul_pd(vscale, x2_im));

    }
}

static __attribute__((target("avx512f,avx512dq,fma"))) void
radix12_n1_scaled_bwd_avx512(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    size_t is, size_t os, size_t vl, double scale)
{
    const __m512d sign_flip = _mm512_set1_pd(-0.0);
    const __m512d KHALF = _mm512_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m512d KS = _mm512_set1_pd(0.866025403784438596588302061718422919511795044);

    __attribute__((aligned(64))) double spill_re[96];
    __attribute__((aligned(64))) double spill_im[96];

    __m512d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im;

    const __m512d tw_W12_1_re = _mm512_set1_pd(W12_1_re);
    const __m512d tw_W12_1_im = _mm512_set1_pd(W12_1_im);
    const __m512d tw_W12_2_re = _mm512_set1_pd(W12_2_re);
    const __m512d tw_W12_2_im = _mm512_set1_pd(W12_2_im);
    const __m512d tw_W12_4_re = _mm512_set1_pd(W12_4_re);
    const __m512d tw_W12_4_im = _mm512_set1_pd(W12_4_im);

    const __m512d vscale = _mm512_set1_pd(scale);

    for (size_t k = 0; k < vl; k += 8) {
        /* sub-FFT n2=0 */
        x0_re = LD(&in_re[0*is+k]);
        x0_im = LD(&in_im[0*is+k]);
        x1_re = LD(&in_re[3*is+k]);
        x1_im = LD(&in_im[3*is+k]);
        x2_re = LD(&in_re[6*is+k]);
        x2_im = LD(&in_im[6*is+k]);
        x3_re = LD(&in_re[9*is+k]);
        x3_im = LD(&in_im[9*is+k]);

        /* radix-4 n2=0 [bwd] */
        {
        __m512d sr=_mm512_add_pd(x0_re,x2_re), si=_mm512_add_pd(x0_im,x2_im);
        __m512d dr=_mm512_sub_pd(x0_re,x2_re), di=_mm512_sub_pd(x0_im,x2_im);
        __m512d tr=_mm512_add_pd(x1_re,x3_re), ti=_mm512_add_pd(x1_im,x3_im);
        __m512d ur=_mm512_sub_pd(x1_re,x3_re), ui=_mm512_sub_pd(x1_im,x3_im);
        x0_re=_mm512_add_pd(sr,tr); x0_im=_mm512_add_pd(si,ti);
        x2_re=_mm512_sub_pd(sr,tr); x2_im=_mm512_sub_pd(si,ti);
        x1_re=_mm512_sub_pd(dr,ui); x1_im=_mm512_add_pd(di,ur);
        x3_re=_mm512_add_pd(dr,ui); x3_im=_mm512_sub_pd(di,ur);
        }

        _mm512_store_pd(&spill_re[0*8], x0_re);
        _mm512_store_pd(&spill_im[0*8], x0_im);
        _mm512_store_pd(&spill_re[1*8], x1_re);
        _mm512_store_pd(&spill_im[1*8], x1_im);
        _mm512_store_pd(&spill_re[2*8], x2_re);
        _mm512_store_pd(&spill_im[2*8], x2_im);
        _mm512_store_pd(&spill_re[3*8], x3_re);
        _mm512_store_pd(&spill_im[3*8], x3_im);

        /* sub-FFT n2=1 */
        x0_re = LD(&in_re[1*is+k]);
        x0_im = LD(&in_im[1*is+k]);
        x1_re = LD(&in_re[4*is+k]);
        x1_im = LD(&in_im[4*is+k]);
        x2_re = LD(&in_re[7*is+k]);
        x2_im = LD(&in_im[7*is+k]);
        x3_re = LD(&in_re[10*is+k]);
        x3_im = LD(&in_im[10*is+k]);

        /* radix-4 n2=1 [bwd] */
        {
        __m512d sr=_mm512_add_pd(x0_re,x2_re), si=_mm512_add_pd(x0_im,x2_im);
        __m512d dr=_mm512_sub_pd(x0_re,x2_re), di=_mm512_sub_pd(x0_im,x2_im);
        __m512d tr=_mm512_add_pd(x1_re,x3_re), ti=_mm512_add_pd(x1_im,x3_im);
        __m512d ur=_mm512_sub_pd(x1_re,x3_re), ui=_mm512_sub_pd(x1_im,x3_im);
        x0_re=_mm512_add_pd(sr,tr); x0_im=_mm512_add_pd(si,ti);
        x2_re=_mm512_sub_pd(sr,tr); x2_im=_mm512_sub_pd(si,ti);
        x1_re=_mm512_sub_pd(dr,ui); x1_im=_mm512_add_pd(di,ur);
        x3_re=_mm512_add_pd(dr,ui); x3_im=_mm512_sub_pd(di,ur);
        }

        _mm512_store_pd(&spill_re[4*8], x0_re);
        _mm512_store_pd(&spill_im[4*8], x0_im);
        _mm512_store_pd(&spill_re[5*8], x1_re);
        _mm512_store_pd(&spill_im[5*8], x1_im);
        _mm512_store_pd(&spill_re[6*8], x2_re);
        _mm512_store_pd(&spill_im[6*8], x2_im);
        _mm512_store_pd(&spill_re[7*8], x3_re);
        _mm512_store_pd(&spill_im[7*8], x3_im);

        /* sub-FFT n2=2 */
        x0_re = LD(&in_re[2*is+k]);
        x0_im = LD(&in_im[2*is+k]);
        x1_re = LD(&in_re[5*is+k]);
        x1_im = LD(&in_im[5*is+k]);
        x2_re = LD(&in_re[8*is+k]);
        x2_im = LD(&in_im[8*is+k]);
        x3_re = LD(&in_re[11*is+k]);
        x3_im = LD(&in_im[11*is+k]);

        /* radix-4 n2=2 [bwd] */
        {
        __m512d sr=_mm512_add_pd(x0_re,x2_re), si=_mm512_add_pd(x0_im,x2_im);
        __m512d dr=_mm512_sub_pd(x0_re,x2_re), di=_mm512_sub_pd(x0_im,x2_im);
        __m512d tr=_mm512_add_pd(x1_re,x3_re), ti=_mm512_add_pd(x1_im,x3_im);
        __m512d ur=_mm512_sub_pd(x1_re,x3_re), ui=_mm512_sub_pd(x1_im,x3_im);
        x0_re=_mm512_add_pd(sr,tr); x0_im=_mm512_add_pd(si,ti);
        x2_re=_mm512_sub_pd(sr,tr); x2_im=_mm512_sub_pd(si,ti);
        x1_re=_mm512_sub_pd(dr,ui); x1_im=_mm512_add_pd(di,ur);
        x3_re=_mm512_add_pd(dr,ui); x3_im=_mm512_sub_pd(di,ur);
        }

        _mm512_store_pd(&spill_re[8*8], x0_re);
        _mm512_store_pd(&spill_im[8*8], x0_im);
        _mm512_store_pd(&spill_re[9*8], x1_re);
        _mm512_store_pd(&spill_im[9*8], x1_im);
        _mm512_store_pd(&spill_re[10*8], x2_re);
        _mm512_store_pd(&spill_im[10*8], x2_im);
        _mm512_store_pd(&spill_re[11*8], x3_re);
        _mm512_store_pd(&spill_im[11*8], x3_im);

        /* PASS 2: 4x radix-3 columns */

        /* column k1=0 */
        x0_re = _mm512_load_pd(&spill_re[0*8]);
        x0_im = _mm512_load_pd(&spill_im[0*8]);
        x1_re = _mm512_load_pd(&spill_re[4*8]);
        x1_im = _mm512_load_pd(&spill_im[4*8]);
        x2_re = _mm512_load_pd(&spill_re[8*8]);
        x2_im = _mm512_load_pd(&spill_im[8*8]);

        /* radix-3 k1=0 [bwd] */
        {
        __m512d sr=_mm512_add_pd(x1_re,x2_re), si=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm512_add_pd(x0_re,sr); x0_im=_mm512_add_pd(x0_im,si);
        x1_re=_mm512_fnmadd_pd(KS,di,Rr); x1_im=_mm512_fmadd_pd(KS,dr,Ri);
        x2_re=_mm512_fmadd_pd(KS,di,Rr); x2_im=_mm512_fnmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[0*os+k], _mm512_mul_pd(vscale, x0_re));
        ST(&out_im[0*os+k], _mm512_mul_pd(vscale, x0_im));
        ST(&out_re[4*os+k], _mm512_mul_pd(vscale, x1_re));
        ST(&out_im[4*os+k], _mm512_mul_pd(vscale, x1_im));
        ST(&out_re[8*os+k], _mm512_mul_pd(vscale, x2_re));
        ST(&out_im[8*os+k], _mm512_mul_pd(vscale, x2_im));

        /* column k1=1 */
        x0_re = _mm512_load_pd(&spill_re[1*8]);
        x0_im = _mm512_load_pd(&spill_im[1*8]);
        x1_re = _mm512_load_pd(&spill_re[5*8]);
        x1_im = _mm512_load_pd(&spill_im[5*8]);
        x2_re = _mm512_load_pd(&spill_re[9*8]);
        x2_im = _mm512_load_pd(&spill_im[9*8]);

        { __m512d tr = x1_re;
          x1_re = _mm512_fmadd_pd(x1_re,tw_W12_1_re,_mm512_mul_pd(x1_im,tw_W12_1_im));
          x1_im = _mm512_fmsub_pd(x1_im,tw_W12_1_re,_mm512_mul_pd(tr,tw_W12_1_im)); }
        { __m512d tr = x2_re;
          x2_re = _mm512_fmadd_pd(x2_re,tw_W12_2_re,_mm512_mul_pd(x2_im,tw_W12_2_im));
          x2_im = _mm512_fmsub_pd(x2_im,tw_W12_2_re,_mm512_mul_pd(tr,tw_W12_2_im)); }

        /* radix-3 k1=1 [bwd] */
        {
        __m512d sr=_mm512_add_pd(x1_re,x2_re), si=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm512_add_pd(x0_re,sr); x0_im=_mm512_add_pd(x0_im,si);
        x1_re=_mm512_fnmadd_pd(KS,di,Rr); x1_im=_mm512_fmadd_pd(KS,dr,Ri);
        x2_re=_mm512_fmadd_pd(KS,di,Rr); x2_im=_mm512_fnmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[1*os+k], _mm512_mul_pd(vscale, x0_re));
        ST(&out_im[1*os+k], _mm512_mul_pd(vscale, x0_im));
        ST(&out_re[5*os+k], _mm512_mul_pd(vscale, x1_re));
        ST(&out_im[5*os+k], _mm512_mul_pd(vscale, x1_im));
        ST(&out_re[9*os+k], _mm512_mul_pd(vscale, x2_re));
        ST(&out_im[9*os+k], _mm512_mul_pd(vscale, x2_im));

        /* column k1=2 */
        x0_re = _mm512_load_pd(&spill_re[2*8]);
        x0_im = _mm512_load_pd(&spill_im[2*8]);
        x1_re = _mm512_load_pd(&spill_re[6*8]);
        x1_im = _mm512_load_pd(&spill_im[6*8]);
        x2_re = _mm512_load_pd(&spill_re[10*8]);
        x2_im = _mm512_load_pd(&spill_im[10*8]);

        { __m512d tr = x1_re;
          x1_re = _mm512_fmadd_pd(x1_re,tw_W12_2_re,_mm512_mul_pd(x1_im,tw_W12_2_im));
          x1_im = _mm512_fmsub_pd(x1_im,tw_W12_2_re,_mm512_mul_pd(tr,tw_W12_2_im)); }
        { __m512d tr = x2_re;
          x2_re = _mm512_fmadd_pd(x2_re,tw_W12_4_re,_mm512_mul_pd(x2_im,tw_W12_4_im));
          x2_im = _mm512_fmsub_pd(x2_im,tw_W12_4_re,_mm512_mul_pd(tr,tw_W12_4_im)); }

        /* radix-3 k1=2 [bwd] */
        {
        __m512d sr=_mm512_add_pd(x1_re,x2_re), si=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm512_add_pd(x0_re,sr); x0_im=_mm512_add_pd(x0_im,si);
        x1_re=_mm512_fnmadd_pd(KS,di,Rr); x1_im=_mm512_fmadd_pd(KS,dr,Ri);
        x2_re=_mm512_fmadd_pd(KS,di,Rr); x2_im=_mm512_fnmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[2*os+k], _mm512_mul_pd(vscale, x0_re));
        ST(&out_im[2*os+k], _mm512_mul_pd(vscale, x0_im));
        ST(&out_re[6*os+k], _mm512_mul_pd(vscale, x1_re));
        ST(&out_im[6*os+k], _mm512_mul_pd(vscale, x1_im));
        ST(&out_re[10*os+k], _mm512_mul_pd(vscale, x2_re));
        ST(&out_im[10*os+k], _mm512_mul_pd(vscale, x2_im));

        /* column k1=3 */
        x0_re = _mm512_load_pd(&spill_re[3*8]);
        x0_im = _mm512_load_pd(&spill_im[3*8]);
        x1_re = _mm512_load_pd(&spill_re[7*8]);
        x1_im = _mm512_load_pd(&spill_im[7*8]);
        x2_re = _mm512_load_pd(&spill_re[11*8]);
        x2_im = _mm512_load_pd(&spill_im[11*8]);

        { __m512d tr = x1_re; x1_re = _mm512_xor_pd(x1_im,sign_flip); x1_im = tr; }
        x2_re = _mm512_xor_pd(x2_re,sign_flip); x2_im = _mm512_xor_pd(x2_im,sign_flip);

        /* radix-3 k1=3 [bwd] */
        {
        __m512d sr=_mm512_add_pd(x1_re,x2_re), si=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d Rr=_mm512_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm512_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm512_add_pd(x0_re,sr); x0_im=_mm512_add_pd(x0_im,si);
        x1_re=_mm512_fnmadd_pd(KS,di,Rr); x1_im=_mm512_fmadd_pd(KS,dr,Ri);
        x2_re=_mm512_fmadd_pd(KS,di,Rr); x2_im=_mm512_fnmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[3*os+k], _mm512_mul_pd(vscale, x0_re));
        ST(&out_im[3*os+k], _mm512_mul_pd(vscale, x0_im));
        ST(&out_re[7*os+k], _mm512_mul_pd(vscale, x1_re));
        ST(&out_im[7*os+k], _mm512_mul_pd(vscale, x1_im));
        ST(&out_re[11*os+k], _mm512_mul_pd(vscale, x2_re));
        ST(&out_im[11*os+k], _mm512_mul_pd(vscale, x2_im));

    }
}


#undef LD
#undef ST

#endif /* FFT_RADIX12_AVX512_CT_CT_N1_SCALED_H */
